 3→import { useMemo, useSyncExternalStore, useRef, useCallback } from "react";
 4→import { useFlowStore } from "@/store/useFlowStore";
 5→import { generateMermaid } from "@/lib/mermaid/generate";
 6→import { serialize } from "@/lib/flowmaid/serialize";
 7→import type { FlowNode, FlowEdge } from "@/store/types";
 8→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
 9→
10→const DEBOUNCE_MS = 200;
11→
12→interface Snapshot {
13→  nodes: FlowNode[];
14→  edges: FlowEdge[];
15→  direction: FlowDirection;
16→  componentDefinitions: ComponentDefinition[];
17→}
18→
19→// Module-level debounced store subscription
20→let currentSnapshot: Snapshot = {
21→  nodes: [],
22→  edges: [],
23→  direction: "TD",
24→  componentDefinitions: [],
25→};
26→let listeners = new Set<() => void>();
27→let timer: ReturnType<typeof setTimeout> | undefined;
28→
29→function getSnapshot() {
30→  return currentSnapshot;
31→}
32→
33→function subscribe(cb: () => void) {
34→  if (listeners.size === 0) {
35→    // Initialize with current store state
36→    const s = useFlowStore.getState();
37→    currentSnapshot = {
38→      nodes: s.nodes,
39→      edges: s.edges,
40→      direction: s.direction,
41→      componentDefinitions: s.componentDefinitions,
42→    };
43→
44→    // Subscribe to store changes with debounce
45→    var unsub = useFlowStore.subscribe((state) => {
46→      clearTimeout(timer);
47→      timer = setTimeout(() => {
48→        const next: Snapshot = {
49→          nodes: state.nodes,
50→          edges: state.edges,
51→          direction: state.direction,
52→          componentDefinitions: state.componentDefinitions,
53→        };
54→        // Only notify if something actually changed
55→        if (
56→          next.nodes !== currentSnapshot.nodes ||
57→          next.edges !== currentSnapshot.edges ||
58→          next.direction !== currentSnapshot.direction ||
59→          next.componentDefinitions !== currentSnapshot.componentDefinitions
60→        ) {
61→          currentSnapshot = next;
62→          listeners.forEach((l) => l());
63→        }
64→      }, DEBOUNCE_MS);
65→    });
66→  }
67→  listeners.add(cb);
68→  return () => {
69→    listeners.delete(cb);
70→    if (listeners.size === 0) {
71→      clearTimeout(timer);
72→      unsub?.();
73→    }
74→  };
75→}
76→
77→export function useMermaidOutput() {
78→  const snap = useSyncExternalStore(subscribe, getSnapshot, getSnapshot);
79→
80→  const mermaid = useMemo(
81→    () => generateMermaid(snap.nodes, snap.edges, snap.direction, snap.componentDefinitions),
82→    [snap.nodes, snap.edges, snap.direction, snap.componentDefinitions]
83→  );
84→
85→  const full = useMemo(
86→    () => serialize(snap.nodes, snap.edges, snap.direction, snap.componentDefinitions),
87→    [snap.nodes, snap.edges, snap.direction, snap.componentDefinitions]
88→  );
89→
90→  return { mermaid, full };
91→}
