  7→/**
  8→ * Generate complete Mermaid flowchart syntax from nodes, edges, and direction
  9→ */
 10→export function generateMermaid(
 11→  nodes: FlowNode[],
 12→  edges: FlowEdge[],
 13→  direction: FlowDirection,
 14→  definitions?: ComponentDefinition[]
 15→): string {
 16→  const lines: string[] = [`graph ${direction}`];
 17→
 18→  // Build map of component instance IDs to their child nodes
 19→  const instanceChildMap = new Map<string, FlowNode[]>();
 20→  const childNodeIds = new Set<string>();
 21→  for (const node of nodes) {
 22→    if (node.data.componentParentId) {
 23→      const parentId = node.data.componentParentId as string;
 24→      if (!instanceChildMap.has(parentId)) instanceChildMap.set(parentId, []);
 25→      instanceChildMap.get(parentId)!.push(node);
 26→      childNodeIds.add(node.id);
 27→    }
 28→  }
 29→
 30→  for (const node of nodes) {
 31→    if (node.data.shape === "text") continue;
 32→    // Skip component children (they're handled within their parent's subgraph)
 33→    if (node.data.componentParentId) continue;
 34→
 35→    // Component instance: expand as subgraph using definition (including Start/End)
 36→    if (node.type === "componentInstance" && node.data.componentDefinitionId) {
 37→      const instanceLabel = escapeMermaid(node.data.componentInstanceName as string ?? node.data.label);
 38→      lines.push(`    subgraph ${node.id}[${instanceLabel}]`);
 39→
 40→      // Get definition to include all nodes (including entry/exit which are excluded from canvas)
 41→      const def = definitions?.find((d) => d.id === node.data.componentDefinitionId);
 42→      if (def) {
 43→        // Output all nodes from definition (including Start/End)
 44→        for (const defNode of def.nodes) {
 45→          const childId = `${node.id}_${defNode.id}`;
 46→          const label = escapeMermaid(defNode.label);
 47→          const shape = defNode.shape;
 48→          let nodeLine: string;
 49→          switch (shape) {
 50→            case "diamond":
 51→              nodeLine = `    ${childId}{${label}}`;
 52→              break;
 53→            case "roundedRect":
 54→              nodeLine = `    ${childId}(${label})`;
 55→              break;
 56→            case "circle":
 57→              nodeLine = `    ${childId}((${label}))`;
 58→              break;
 59→            case "stadium":
 60→              nodeLine = `    ${childId}([${label}])`;
 61→              break;
 62→            default:
 63→              nodeLine = `    ${childId}[${label}]`;
 64→          }
 65→          lines.push(nodeLine);
 66→        }
 67→
 68→        // Output all internal edges from definition (including Start/End edges)
 69→        for (const defEdge of def.edges) {
 70→          const srcId = `${node.id}_${defEdge.source}`;
 71→          const tgtId = `${node.id}_${defEdge.target}`;
 72→          const label = defEdge.label;
 73→          if (label) {
 74→            lines.push(`    ${srcId} -->|${escapeMermaid(label)}| ${tgtId}`);
 75→          } else {
 76→            lines.push(`    ${srcId} --> ${tgtId}`);
 77→          }
 78→        }
 79→      } else {
 80→        // Fallback: use actual child nodes if definition not found
 81→        const children = instanceChildMap.get(node.id) ?? [];
 82→        for (const child of children) {
 83→          const label = escapeMermaid(child.data.label);
 84→          const shape = child.data.shape;
 85→          let nodeLine: string;
 86→          switch (shape) {
 87→            case "diamond":
 88→              nodeLine = `    ${child.id}{${label}}`;
 89→              break;
 90→            case "roundedRect":
 91→              nodeLine = `    ${child.id}(${label})`;
 92→              break;
 93→            case "circle":
 94→              nodeLine = `    ${child.id}((${label}))`;
 95→              break;
 96→            case "stadium":
 97→              nodeLine = `    ${child.id}([${label}])`;
 98→              break;
 99→            default:
100→              nodeLine = `    ${child.id}[${label}]`;
101→          }
102→          lines.push(nodeLine);
103→        }
104→
105→        for (const edge of edges) {
106→          if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) {
107→            const srcNode = nodes.find((n) => n.id === edge.source);
108→            const tgtNode = nodes.find((n) => n.id === edge.target);
109→            if (srcNode?.data.componentParentId === node.id && tgtNode?.data.componentParentId === node.id) {
110→              const label = edge.data?.label;
111→              if (label) {
112→                lines.push(`    ${edge.source} -->|${escapeMermaid(label)}| ${edge.target}`);
113→              } else {
114→                lines.push(`    ${edge.source} --> ${edge.target}`);
115→              }
116→            }
117→          }
118→        }
119→      }
120→
121→      lines.push(`    end`);
122→      continue;
123→    }
124→
125→    lines.push(nodeToMermaid(node));
126→  }
127→
128→  for (const edge of edges) {
129→    // Skip bridge edges
130→    if (edge.data?.isBridgeEdge) continue;
131→    // Skip internal edges (already handled in subgraph)
132→    if (childNodeIds.has(edge.source) && childNodeIds.has(edge.target)) continue;
133→
134→    // For edges connected to component instances, remap to entry/exit child nodes
135→    if (definitions) {
136→      let source = edge.source;
137→      let target = edge.target;
138→
139→      const sourceNode = nodes.find((n) => n.id === source);
140→      const targetNode = nodes.find((n) => n.id === target);
141→
142→      if (sourceNode?.type === "componentInstance" && sourceNode.data.componentDefinitionId) {
143→        const def = definitions.find((d) => d.id === sourceNode.data.componentDefinitionId);
144→        if (def?.exitNodeId) {
145→          source = `${sourceNode.id}_${def.exitNodeId}`;
146→        }
147→      }
148→      if (targetNode?.type === "componentInstance" && targetNode.data.componentDefinitionId) {
149→        const def = definitions.find((d) => d.id === targetNode.data.componentDefinitionId);
150→        if (def?.entryNodeId) {
151→          target = `${targetNode.id}_${def.entryNodeId}`;
152→        }
153→      }
154→
155→      if (source !== edge.source || target !== edge.target) {
156→        const label = edge.data?.label;
157→        if (label) {
158→          lines.push(`    ${source} -->|${escapeMermaid(label)}| ${target}`);
159→        } else {
160→          lines.push(`    ${source} --> ${target}`);
161→        }
162→        continue;
163→      }
164→    }
165→
166→    lines.push(edgeToMermaid(edge));
167→  }
168→
169→  return lines.join("\n");
170→}
