61→          currentSnapshot = next;
62→          listeners.forEach((l) => l());
63→        }
64→      }, DEBOUNCE_MS);
65→    });
66→  }
67→  listeners.add(cb);
68→  return () => {
69→    listeners.delete(cb);
70→    if (listeners.size === 0) {
71→      clearTimeout(timer);
72→      unsub?.();
73→    }
74→  };
75→}
