  1→import { stringify, parse } from "yaml";
  2→import { generateMermaid } from "@/lib/mermaid/generate";
  3→import type { FlowNode, FlowEdge } from "@/store/types";
  4→import type { FlowDirection, ComponentDefinition } from "@/types/flow";
  5→import type { FlowmaidLayout, FlowmaidNodeLayout, FlowmaidEdgeLayout } from "./schema";
  6→
  7→export function serialize(
  8→  nodes: FlowNode[],
  9→  edges: FlowEdge[],
 10→  direction: FlowDirection,
 11→  componentDefinitions?: ComponentDefinition[]
 12→): string {
 13→  const mermaidSection = generateMermaid(nodes, edges, direction, componentDefinitions);
 14→
 15→  const nodesLayout: Record<string, FlowmaidNodeLayout> = {};
 16→  for (const node of nodes) {
 17→    // Skip component child nodes (they're regenerated from definition)
 18→    if (node.data.componentParentId) continue;
 19→    const styleW = (node.style as Record<string, unknown>)?.width as number | undefined;
 20→    const styleH = (node.style as Record<string, unknown>)?.height as number | undefined;
 21→    const w = node.width ?? styleW;
 22→    const h = node.height ?? styleH;
 23→
 24→    const entry: FlowmaidNodeLayout = {
 25→      position: { x: node.position.x, y: node.position.y },
 26→      size: w && h ? { width: w, height: h } : undefined,
 27→      shape: node.data.shape,
 28→      label: node.data.label,
 29→    };
 30→    if (node.data.fillColor) entry.fillColor = node.data.fillColor;
 31→    if (node.data.fillOpacity !== undefined && node.data.fillOpacity !== 10) entry.fillOpacity = node.data.fillOpacity;
 32→    if (node.data.fillLightness !== undefined && node.data.fillLightness !== 5) entry.fillLightness = node.data.fillLightness;
 33→    if (node.data.borderColor) entry.borderColor = node.data.borderColor;
 34→    if (node.data.borderOpacity !== undefined && node.data.borderOpacity !== 10) entry.borderOpacity = node.data.borderOpacity;
 35→    if (node.data.borderLightness !== undefined && node.data.borderLightness !== 5) entry.borderLightness = node.data.borderLightness;
 36→    if (node.data.borderWidth) entry.borderWidth = node.data.borderWidth;
 37→    if (node.data.borderStyle) entry.borderStyle = node.data.borderStyle;
 38→    if (node.zIndex !== undefined && node.zIndex !== 0) entry.zIndex = node.zIndex;
 39→    if (node.data.fontSize) entry.fontSize = node.data.fontSize;
 40→    if (node.data.textColor) entry.textColor = node.data.textColor;
 41→    if (node.data.textOpacity !== undefined && node.data.textOpacity !== 10) entry.textOpacity = node.data.textOpacity;
 42→    if (node.data.textLightness !== undefined && node.data.textLightness !== 5) entry.textLightness = node.data.textLightness;
 43→    if (node.data.textAlign && node.data.textAlign !== "center") entry.textAlign = node.data.textAlign;
 44→    if (node.data.bold) entry.bold = node.data.bold;
 45→    if (node.data.italic) entry.italic = node.data.italic;
 46→    if (node.data.underline) entry.underline = node.data.underline;
 47→    if (node.data.componentDefinitionId) entry.componentDefinitionId = node.data.componentDefinitionId as string;
 48→    if (node.data.componentInstanceName) entry.componentInstanceName = node.data.componentInstanceName as string;
 49→    if (node.data.componentSyncVersion !== undefined) entry.componentSyncVersion = node.data.componentSyncVersion as number;
 50→    if (node.data.collapsed) entry.collapsed = true;
 51→    if (node.data.expandedSize) entry.expandedSize = node.data.expandedSize as { width: number; height: number };
 52→
 53→    nodesLayout[node.id] = entry;
 54→  }
 55→
 56→  // Build set of component child node IDs to filter internal edges
 57→  const componentChildIds = new Set(nodes.filter((n) => n.data.componentParentId).map((n) => n.id));
 58→
 59→  const edgesLayout: Record<string, FlowmaidEdgeLayout> = {};
 60→  for (const edge of edges) {
 61→    // Skip bridge edges
 62→    if (edge.data?.isBridgeEdge) continue;
 63→    // Skip internal edges between component children
 64→    if (componentChildIds.has(edge.source) && componentChildIds.has(edge.target)) continue;
 65→    const entry: FlowmaidEdgeLayout = {
 66→      source: edge.source,
 67→      target: edge.target,
 68→    };
 69→    if (edge.data?.label) entry.label = edge.data.label;
 70→    if (edge.sourceHandle) entry.sourceHandle = edge.sourceHandle;
 71→    if (edge.targetHandle) entry.targetHandle = edge.targetHandle;
 72→    if (edge.data?.edgeType && edge.data.edgeType !== "bezier") entry.edgeType = edge.data.edgeType;
 73→    if (edge.data?.markerStart) entry.markerStart = edge.data.markerStart;
 74→    if (edge.data?.markerEnd && edge.data.markerEnd !== "arrowclosed") entry.markerEnd = edge.data.markerEnd;
 75→    if (edge.data?.strokeWidth && edge.data.strokeWidth !== 2) entry.strokeWidth = edge.data.strokeWidth;
 76→    if (edge.data?.strokeColor) entry.strokeColor = edge.data.strokeColor;
 77→    if (edge.data?.strokeOpacity !== undefined && edge.data.strokeOpacity !== 10) entry.strokeOpacity = edge.data.strokeOpacity;
 78→    if (edge.data?.strokeLightness !== undefined && edge.data.strokeLightness !== 5) entry.strokeLightness = edge.data.strokeLightness;
 79→    if (edge.data?.strokeStyle && edge.data.strokeStyle !== "solid") entry.strokeStyle = edge.data.strokeStyle;
 80→    if (edge.data?.waypoints && edge.data.waypoints.length > 0) entry.waypoints = edge.data.waypoints;
 81→
 82→    edgesLayout[edge.id] = entry;
 83→  }
 84→
 85→  const layout: FlowmaidLayout = {
 86→    direction,
 87→    nodes: nodesLayout,
 88→    edges: edgesLayout,
 89→    ...(componentDefinitions && componentDefinitions.length > 0 && { componentDefinitions }),
 90→  };
 91→
 92→  const layoutSection = stringify(layout);
 93→
 94→  return `--- mermaid ---\n${mermaidSection}\n\n--- layout ---\n${layoutSection}`;
 95→}
 96→
 97→/**
 98→ * Serialize only the selected nodes/edges (+ related edges) for filtered preview.
 99→ * Returns the same format as serialize() but with only the relevant layout entries.
100→ * Mermaid section is always included in full.
101→ */
102→export function serializeFiltered(
103→  nodes: FlowNode[],
104→  edges: FlowEdge[],
105→  direction: FlowDirection,
106→  componentDefinitions: ComponentDefinition[] | undefined,
107→  selectedNodeIds: string[],
108→  selectedEdgeIds: string[]
109→): string {
110→  const full = serialize(nodes, edges, direction, componentDefinitions);
111→  if (selectedNodeIds.length === 0 && selectedEdgeIds.length === 0) return full;
112→
113→  const parts = full.split("--- layout ---\n");
114→  if (parts.length < 2) return full;
115→
116→  const mermaidPart = parts[0];
117→  const layoutYaml = parts[1];
118→
119→  const layout = parse(layoutYaml) as FlowmaidLayout | null;
120→  if (!layout) return full;
121→
122→  const nodeIdSet = new Set(selectedNodeIds);
123→  const edgeIdSet = new Set(selectedEdgeIds);
124→
125→  const filteredLayout: FlowmaidLayout = {
126→    direction: layout.direction,
127→    nodes: {},
128→    edges: {},
129→  };
130→
131→  if (layout.nodes) {
132→    for (const [id, node] of Object.entries(layout.nodes)) {
133→      if (nodeIdSet.has(id)) filteredLayout.nodes[id] = node;
134→    }
135→  }
136→  if (layout.edges) {
137→    for (const [id, edge] of Object.entries(layout.edges)) {
138→      if (edgeIdSet.has(id)) filteredLayout.edges[id] = edge;
139→    }
140→  }
141→  if (layout.componentDefinitions) {
142→    filteredLayout.componentDefinitions = layout.componentDefinitions;
143→  }
144→
145→  const filteredSection = stringify(filteredLayout);
146→
147→  return `${mermaidPart}--- layout ---\n${filteredSection}`;
148→}
