              width={leftWidth}
              ribbonLabel="Nodes"
            >
              <NodePalette />
            </CollapsiblePanel>

            <ResizablePanelGroup orientation="horizontal" className="flex-1">
              <ResizablePanel defaultSize={rightOpen ? 70 : 100} minSize={30}>
                <FlowCanvas />
              </ResizablePanel>

              {rightOpen && (
                <>
                  <ToggleResizeHandle onClick={toggleRight} />
                  <ResizablePanel defaultSize={30} minSize={15}>
                    <MermaidPreview />
                  </ResizablePanel>
                </>
              )}
            </ResizablePanelGroup>

            {!rightOpen && (
              <ToggleRibbon onClick={toggleRight} />
            )}
          </div>
          )}
          </div>
        </div>
        <input
          ref={fileInputRef}
          type="file"
          accept=".flowmaid"
          className="hidden"
          onChange={handleFileChange}
        />
        <MermaidImportDialog
          open={mermaidImportOpen}
          onOpenChange={setMermaidImportOpen}
          onSuccess={handleFitView}
        />
        <ExportDialog
          open={exportDialogOpen}
          onOpenChange={setExportDialogOpen}
        />
        <BetaNoticeDialog />
      </DnDProvider>
    </ReactFlowProvider>
  );
}
